const raw = String($json.stdout || '').trim();
if (!raw) throw new Error('FFmpeg提取单帧没有返回 stdout');

let parsed;
try { parsed = JSON.parse(raw); }
catch(e) { throw new Error(`解析抽帧结果失败: ${e.message}; 原始输出: ${raw}`); }

const sceneDataBase64 = parsed.sceneDataBase64 || '';
if (!sceneDataBase64) throw new Error('缺少 sceneDataBase64');

let sceneData;
try { sceneData = JSON.parse(Buffer.from(sceneDataBase64,'base64').toString('utf8')); }
catch(e) { throw new Error(`sceneDataBase64 解码失败: ${e.message}`); }

const base = $('提取场景关键帧').item.json;
return {
  json: {
    taskId: parsed.taskId, order: parsed.order, fileName: parsed.fileName, outputPath: parsed.outputPath,
    supabase_url: base.supabase_url, supabase_api_key: base.supabase_api_key, supabase_bucket: base.supabase_bucket || 'uploads',
    sceneDataBase64, sceneData, ...sceneData
  }
};

function text(v) {
  return v == null ? '' : String(v).trim();
}

function toPretty(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value.trim();
  try {
    return JSON.stringify(value, null, 2);
  } catch {
    return String(value);
  }
}

function joinBlocks(blocks) {
  return blocks.filter(Boolean).join('\n\n').trim();
}

function getFileName(meta) {
  const direct =
    text(meta.fileName) ||
    text(meta.filename) ||
    text(meta.file_name) ||
    text(meta.name) ||
    text(meta.Key) ||
    text(meta.key);

  if (direct) return direct;

  const outputPath = text(meta.outputPath || meta.output_path || meta.path);
  if (outputPath) {
    const cleaned = outputPath.split('?')[0];
    const parts = cleaned.split('/').filter(Boolean);
    return parts.length ? parts[parts.length - 1] : '';
  }

  const url = text(meta.publicUrl || meta.public_url || meta.url);
  if (url) {
    const cleaned = url.split('?')[0];
    const parts = cleaned.split('/').filter(Boolean);
    return parts.length ? parts[parts.length - 1] : '';
  }

  return '';
}

function simplifySellingPoints(raw, maxLen = 120) {
  const s = text(raw);
  if (!s) return '';

  const cleaned = s
    .replace(/\s+/g, ' ')
    .replace(/[•●▪\-]\s*/g, '')
    .trim();

  if (cleaned.length <= maxLen) return cleaned;

  const cut = cleaned.slice(0, maxLen);
  const lastPunc = Math.max(
    cut.lastIndexOf('。'),
    cut.lastIndexOf('，'),
    cut.lastIndexOf('.'),
    cut.lastIndexOf(','),
    cut.lastIndexOf(';'),
    cut.lastIndexOf('；')
  );

  return (lastPunc > 20 ? cut.slice(0, lastPunc) : cut).trim();
}

function buildMotion(sceneData, fallbackActionBlocking) {
  const m = sceneData.video_motion_plan || {};
  const start = text(m.start_state);
  const b1 = text(m.motion_beat_1);
  const b2 = text(m.motion_beat_2);
  const b3 = text(m.motion_beat_3);
  const end = text(m.end_state);

  const lines = [
    start && `The shot starts with ${start}.`,
    b1 && `Then ${b1}.`,
    b2 && `Then ${b2}.`,
    b3 && `Then ${b3}.`,
    end && `The shot ends with ${end}.`
  ].filter(Boolean);

  if (!lines.length && fallbackActionBlocking) {
    return `The main action flow is: ${fallbackActionBlocking}.`;
  }

  return lines.join('\n');
}

const meta = $json || {};
const sceneData = meta.sceneData || {};
const base = $('准备参数').first().json || {};

const supabaseUrl = text(meta.supabase_url || base.supabase_url);
const bucket = text(meta.supabase_bucket || base.supabase_bucket || 'uploads');
const taskId = text(meta.taskId || meta.task_id || base.taskId || base.task_id);
const fileName = getFileName(meta);

const ossUrl = text(meta.url || '');
const publicUrl =
  ossUrl ||
  (supabaseUrl && taskId && fileName
    ? `${supabaseUrl}/storage/v1/object/public/${bucket}/${taskId}/${fileName}`
    : '');

const productName = text(base.productName || base.product_name);
const productDescription = text(base.productDescription || base.product_description);

const rawProductSellingPoints = text(
  base.productSellingPoints || base.product_selling_points
);
const primaryProductBenefit = simplifySellingPoints(rawProductSellingPoints, 80);

const characterName = text(
  base.characterName ||
  base.character_name ||
  base.characterId ||
  base.character_id
);

const shotGoal = text(sceneData.shot_goal);
const visualContentDescription = text(sceneData.visual_content_description);
const locationSetting = text(sceneData.location_setting);
const characterDesc = text(sceneData.character_desc);
const emotionState = text(sceneData.emotion_state);
const actionBlocking = text(sceneData.action_blocking);
const productDesc = text(sceneData.product_desc);
const mustShow = text(sceneData.must_show);
const onScreenTextGraphics = text(sceneData.on_screen_text_graphics);

const cameraShotSize = text(sceneData.camera_shot_size);
const cameraAngle = text(sceneData.camera_angle);
const cameraMovement = text(sceneData.camera_movement);
const compositionNotes = text(sceneData.composition_notes);

const lightingAtmosphere = text(sceneData.lighting_atmosphere);
const colorGrading = text(sceneData.color_grading);

const pacingNotes = text(sceneData.pacing_notes);
const editingTransition = text(sceneData.editing_transition);

const cameraNotes = text(sceneData.camera_notes);
const lightingNotes = text(sceneData.lighting_notes);

const lockedElements = toPretty(sceneData.locked_elements);
const replaceableElements = toPretty(sceneData.replaceable_elements);
const characterContinuityRules = toPretty(sceneData.character_continuity_rules);
const productContinuityRules = toPretty(sceneData.product_continuity_rules);

const hasPerson = meta.has_person === true || sceneData.has_person === true;
const hasProduct = meta.has_product === true || sceneData.has_product === true;

const motionText = buildMotion(sceneData, actionBlocking);

const finalImagePrompt = joinBlocks([
  `You are rebuilding a commercial still from a source-video shot for viral-clone production.`,

  `Core rule:
Preserve the original shot design, composition, camera logic, scene structure, lighting logic, emotional purpose, and action staging.
Only replace subject identity where applicable.
Do not redesign the shot.`,

  `Reference image usage rules:
- The reference frame image is the primary anchor for composition, crop, perspective, camera height, subject placement, scene layout, background structure, lighting direction, shadow logic, and storytelling purpose.
- The character reference image, if provided, is only for replacing and locking character identity, including face identity, hairstyle, body type, and appearance consistency.
- The product reference image, if provided, is only for replacing and locking product identity, including shape, proportion, material, surface finish, packaging form, and branding structure.
- Do not let the character reference image change the shot design.
- Do not let the product reference image change the shot design.
