const finalVideoPrompt = joinBlocks([
  `Create one single continuous photorealistic commercial video shot, not a storyboard outline and not a rule list.`,

  `Reconstruct the original source-video shot faithfully, using the reference frame as the composition and staging anchor.`,

  `Shot identity:
